Spesifik exceptionlar tercih edilmelidir. Genel except beklenmedik hatalari gizler ve debugging'i zorlastirir:

# Kotu
 try:
    sonuc = 10 / sayi
except:
    print("Hata")

# Iyi
try:
    sonuc = 10 / sayi
except ZeroDivisionError:
    print("Sifira bolme hatasi")
except TypeError:
    print("Sayi olmali")

Context manager kaynaklarin guvenli sekilde yonetilmesini saglar. with blogu cikis yaparken kaynagi otomatik temizler:

class VeritabaniBaglantisi:
    def __enter__(self):
        self.baglanti = baglan()
        return self.baglanti
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.baglanti.kapat()

with VeritabaniBaglantisi() as baglanti:
    baglanti.sorgula("SELECT * FROM tablo")

is None veya is not None kullanilmalidir. == None bazen hatali sonuc verebilir:

# Dogru
if deger is None:
    print("Deger None")

# Dogru
if deger is not None:
    print("Deger var")

# Yanlis (ozel durumlar haric)
