var'in function scope problemi ve hosting karisikligina yol actigi icin kullanimi tavsiye edilmez.

Promise veya async/await tercih edilmelidir. Callback'ler callback hell'e yol acar:

// Kotu - callback hell
fetchData(function(data) {
    processData(data, function(result) {
        saveResult(result, function() {
            console.log("Kaydedildi");
        });
    });
});

// Iyi - async/await
async function handleData() {
    const data = await fetchData();
    const result = await processData(data);
    await saveResult(result);
    console.log("Kaydedildi");
}

Event listener'lar, interval'lar ve referanslar temizlenmelidir:

// Kotu
window.addEventListener('resize', handleResize);
setInterval(doSomething, 1000);

// Iyi - temizleme ekle
window.addEventListener('resize', handleResize);
const intervalId = setInterval(doSomething, 1000);

// Temizle
window.removeEventListener('resize', handleResize);
clearInterval(intervalId);

DocumentFragment kullanarak toplu DOM guncellemeleri yapilmalidir. Her DOM manipulasyonu reflow tetikler:

// Kotu - her seferinde reflow
for (let i = 0; i < 100; i++) {
    ul.appendChild(li);
}

// Iyi - tek seferde
const fragment = document.createDocumentFragment();
for (let i = 0; i < 100; i++) {
    fragment.appendChild(li);
}
ul.appendChild(fragment);

Java 8 ile gelen Optional sinifi kullanilmalidir. Ayrica Objects.requireNonNull() ve @NotNull anotasyonu da faydalidir:

// Kotu
public String getSehir(Kullanici k) {
    return k.getAdres().getSehir();
}

// Iyi
public Optional<String> getSehir(Kullanici k) {
    return Optional.ofNullable(k)
        .map(Kullanici::getAdres)
        .map(Adres::getSehir);
}

try-with-resources kaynaklari otomatik kapatir, finally blogu gerektirmez ve daha guvenlidir:

// Kotu
BufferedReader br = new BufferedReader(new FileReader("dosya.txt"));
try {
    return br.readLine();
} finally {
    br.close();
}

// Iyi
try (BufferedReader br = new BufferedReader(new FileReader("dosya.txt"))) {
    return br.readLine();
}

String immutabledir, her + islemi yeni bir nesne olusturur. StringBuilder mutable oldugu icin birlestirme islemlerinde cok daha verimlidir:

// Kotu - cok sayida string birlestirme
String sonuc = "";
for (String s : kelimeler) {
    sonuc += s + " ";
}

// Iyi - StringBuilder
StringBuilder sb = new StringBuilder();
for (String s : kelimeler) {
    sb.append(s).append(" ");
}
String sonuc = sb.toString().trim();

HashMap, HashSet gibi koleksiyonlar hashCode() ile calisir. Eger equals() degistirilirse hashCode() da uyumlu olmali, yoksa nesneler koleksiyonlarda dogru calismaz:

@Override
public boolean equals(Object o) {
    if (this == o) return true;
    if (o == null || getClass() != o.getClass()) return false;
    Kullanici that = (Kullanici) o;
    return id == that.id;
}

@Override
public int hashCode() {
    return Objects.hash(id);
}

Any tipi tip guvenligini ortadan kaldirir. Bunun yerine unknown, generic tipler veya union tipler kullanilmalidir:

// Kotu
function yazdir(data: any) {
    console.log(data.name);
}

// Iyi
function yazdir(data: Record<string, unknown>) {
    if ('name' in data && typeof data.name === 'string') {
        console.log(data.name);
    }
}

// Daha iyi - generic
function yazdir<T extends { name: string }>(data: T) {
    console.log(data.name);
}

Strict null checks acik olmali ve optional chaining kullanilmalidir:

// tsconfig.json: "strictNullChecks": true

// Kotu
if (kullanici && kullanici.adres && kullanici.adres.sehir) {
    console.log(kullanici.adres.sehir);
}

// Iyi - optional chaining
console.log(kullanici?.adres?.sehir);

// Nullish coalescing
const sehir = kullanici?.adres?.sehir ?? "Bilinmiyor";

String enumlar yerine const nesne + union type kullanmak daha guvenlidir. Enumlar runtime'da ek kod olusturur:

// Kotu - runtime overhead
enum Status {
    AKTIF = "AKTIF",
    PASIF = "PASIF"
}

// Iyi - type-safe, extra kod yok
const Status = {
    AKTIF: "AKTIF",
    PASIF: "PASIF"
} as const;

type Status = typeof Status[keyof typeof Status];

Go'da exception yoktur, hatalar donus degeri olarak dondurulur. Her hata kontrol edilmelidir:

// Iyi - hata kontrolu
dosya, err := os.Open("dosya.txt")
if err != nil {
    return fmt.Errorf("dosya acilamadi: %w", err)
}
defer dosya.Close()

// Hata sarmalama (wrapping) ile baglam korunur
func islemYap() error {
    err := veriOku()
    if err != nil {
        return fmt.Errorf("islem basarisiz: %w", err)
    }
    return nil
}

defer, bir fonksiyonun bitiminde calistirilmasi gereken islemler icin kullanilir, genelde kaynak temizligi icin:

func dosyaOku(yol string) ([]byte, error) {
    dosya, err := os.Open(yol)
    if err != nil {
        return nil, err
    }
    defer dosya.Close()  // Fonksiyon bitince calisir

    return ioutil.ReadAll(dosya)
}

// Birden fazla defer LIFO sirasiyla calisir
func kaynakYonet() {
    defer fmt.Println("ilk acilan, son kapanan")
    defer fmt.Println("son acilan, ilk kapanan")
}

Channel'lar goroutine'ler arasi iletisim icin, mutex'ler ise paylasilan state korumak icin kullanilir. Go felsefesi: "Iletisim kurarak belleği paylasma, belleği paylasarak iletisim kurma":

// Channel ile
func topla(sayilar []int, c chan int) {
    toplam := 0
    for _, s := range sayilar {
        toplam += s
    }
    c <- toplam
}

// Mutex ile
type GuvenliSayaç struct {
    mu     sync.Mutex
    deger int
}
func (s *GuvenliSayaç) Artir() {
    s.mu.Lock()
    defer s.mu.Unlock()
    s.deger++
}

